insert into questions (public_id,body,target_count,body_locale,language_hint,source,visibility,moderation_state,status,category_slug,playlist_slugs,synonyms,hint_seeds_ru,frame_hint_ru,taxonomy,editorial_flags,editor_note,is_featured,card_of_day_weight,onboarding_safe,team_safe,search_index_text_ru) values ('qtx-0138', 'Если бы твоя текущая модель ситуации оказалась неверной — что бы изменилось?', 5, 'ru', 'ru', 'seed', 'public', 'ok', 'approved', 'modelling', '["systems_thinking"]'::jsonb, '["Что ты сделал бы иначе, если бы ты ошибался в своём понимании этой ситуации?","Представь, что твоя интерпретация происходящего полностью неверна — как тогда выглядит ситуация?"]'::jsonb, '["границы карты","масштаб ×10","масштаб ÷10"]'::jsonb, 'Карта не территория — ищи, где они расходятся.', '{"primary_class":"generative","purpose":["development","creative"],"domains":["thinking","work","project"],"answer_form":"description","openness":"open","complexity":"advanced","generativity_score":4,"modes":["individual","pair","deep_session"],"time_focus":"present"}'::jsonb, '["high_generativity","counterintuitive"]'::jsonb, 'Инвертирует уверенность в модели — генерирует новые версии ситуации.', false, 1, false, false, 'Если бы твоя текущая модель ситуации оказалась неверной — что бы изменилось? Что ты сделал бы иначе, если бы ты ошибался в своём понимании этой ситуации? Представь, что твоя интерпретация происходящего полностью неверна — как тогда выглядит ситуация? Генеративные Моделирование Системное мышление Развитие Креатив Мышление Работа Проект Описание Открытый Продвинутый Индивидуально В паре Глубокая сессия Настоящее') on conflict (public_id) do nothing;
